export class ConnectionFactory {
  static build(env: NodeJS.ProcessEnv) {
    if (env.API_PG_DB_HOST) return new PostgresConnection(env);
    if (env.MYSQL_HOST) return new MysqlConnection(env);
    throw new Error('No supported DB configured');
  }
}

